select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where u.id = p.owneruserid and u.id = b.userid and p.id = c.postid and p.id = ph.postid and p.id = v.postid and p.posttypeid=1 and p.commentcount>=0 and p.commentcount<=12 and p.favoritecount>=0 and v.bountyamount<=50;
